// ========== CONFIGURACIÓN ==========
// Usa variables de entorno o edita los valores aquí

var lat = env.get('AWTRIX_LAT') || '19.4326';
var lon = env.get('AWTRIX_LON') || '-99.1332';
var apiKey = env.get('OPENWEATHER_API_KEY') || 'TU_API_KEY_AQUI';
var awtrixIP = env.get('AWTRIX_IP') || '192.168.1.108';

// ======================================

if (apiKey === 'TU_API_KEY_AQUI') {
    node.error('Falta configurar OPENWEATHER_API_KEY');
    return null;
}

msg.lat = lat;
msg.lon = lon;
msg.apiKey = apiKey;
msg.awtrixIP = awtrixIP;

msg.url = `http://api.openweathermap.org/data/2.5/air_pollution?lat=${lat}&lon=${lon}&appid=${apiKey}`;

return msg;

// Obtener datos de OpenWeather
var data = msg.payload;

if (!data || !data.list || !data.list[0]) {
    node.error('No se recibieron datos de OpenWeather');
    return null;
}

var pollution = data.list[0];
var components = pollution.components;

// PM2.5 es el indicador principal para ICA
var pm25 = components.pm2_5;
var pm10 = components.pm10;
var o3 = components.o3;
var no2 = components.no2;
var co = components.co;

// Calcular AQI basado en PM2.5 (escala US EPA)
function calcAQI_PM25(pm25) {
    var breakpoints = [
        {low: 0, high: 12, aqiLow: 0, aqiHigh: 50},
        {low: 12.1, high: 35.4, aqiLow: 51, aqiHigh: 100},
        {low: 35.5, high: 55.4, aqiLow: 101, aqiHigh: 150},
        {low: 55.5, high: 150.4, aqiLow: 151, aqiHigh: 200},
        {low: 150.5, high: 250.4, aqiLow: 201, aqiHigh: 300},
        {low: 250.5, high: 500.4, aqiLow: 301, aqiHigh: 500}
    ];

    for (var bp of breakpoints) {
        if (pm25 >= bp.low && pm25 <= bp.high) {
            return Math.round(
                ((bp.aqiHigh - bp.aqiLow) / (bp.high - bp.low)) * 
                (pm25 - bp.low) + bp.aqiLow
            );
        }
    }
    return 500;
}

// Calcular AQI
var aqi = calcAQI_PM25(pm25);

// Determinar color y texto según AQI
var color, status, icon;

if (aqi <= 50) {
    color = '#00E400';
    status = 'Bueno';
    icon = 13209;
} else if (aqi <= 100) {
    color = '#FFFF00';
    status = 'Moderado';
    icon = 13210;
} else if (aqi <= 150) {
    color = '#FF7E00';
    status = 'Insalubre*';
    icon = 13211;
} else if (aqi <= 200) {
    color = '#FF0000';
    status = 'Insalubre';
    icon = 13212;
} else if (aqi <= 300) {
    color = '#8F3F97';
    status = 'Muy insalubre';
    icon = 13213;
} else {
    color = '#7E0023';
    status = 'Peligroso';
    icon = 13214;
}

// Preparar payload para AWTRIX 3
msg.payload = {
    'text': `ICA ${aqi}`,
    'icon': 4080,
    'color': color,
    'duration': 10,
    'pushIcon': 0,
    'lifetime': 900
};

// URL para HTTP API de AWTRIX
msg.url = `http://${msg.awtrixIP}/api/custom?name=aqi`;
msg.method = 'POST';
msg.headers = {'Content-Type': 'application/json'};

// Log para debug
node.warn(`ICA: ${aqi} | PM2.5: ${pm25} | Status: ${status}`);

return msg;
